      "imagePrompt": "A browser showing a “404 Not Found” page. Address bar: `https://example.com/products/shoes?color=blue`. A site map panel says `Shoes page: /shop/shoes`.",
      "options": [
        {
          "feedback": "The path names the resource on the server. The link points to `/products/shoes`, but the site map shows the page is at `/shop/shoes`, so the path is the part to repair.",
          "isCorrect": true,
          "text": "Update the path"
        },
        {
          "feedback": "Removing the query would discard the blue filter, but the 404 comes from requesting the wrong page location. The path must change from `/products/shoes` to `/shop/shoes`.",
          "isCorrect": false,
          "text": "Remove the query"
        },
        {
          "feedback": "Switching to `http` changes the protocol, not the page location. The evidence points to a wrong path because the page is stored at `/shop/shoes`.",
          "isCorrect": false,
          "text": "Switch to `http`"
        },
        {
          "feedback": "A fragment would only jump to a spot within a loaded page. The page itself is not found, so the repair is to update the path to the stored page location.",
          "isCorrect": false,
          "text": "Change the fragment"
        }
      ],
      "question": "Which repair should the link use?"
    },
    {
      "dialogue": "The library stays on the search page, but the results are for `climate` instead of `volcano`. The visible values after `?` are `q=climate&page=1`.",
      "imagePrompt": "A library search page with address bar `https://library.example.org/search?q=climate&page=1`; search results headed “Results for climate” while a note says “User wanted volcano”.",
      "options": [
        {
          "feedback": "The query string is the part after `?`. It carries values such as `q=climate`, so editing that value to the wanted search term changes the filtered results while staying on `/search`.",
          "isCorrect": true,
          "text": "Query string"
        },
        {
          "feedback": "The path `/search` is already the correct search page. The wrong result term is in the values after `?`, so the query string is the part to edit.",
          "isCorrect": false,
          "text": "Path"
        },
        {
          "feedback": "A fragment would move to a section of the page, not change the search term. The search value is in the query string after `?`.",
          "isCorrect": false,
          "text": "Fragment"
        },
        {
          "feedback": "The domain chooses the library site. The page is already on the right site; the unwanted search term is carried in the query string.",
          "isCorrect": false,
          "text": "Domain"
        }
      ],
      "question": "Which URL part should be edited to get the wanted results?"
