      "imagePrompt": "A browser with address bar `https://news.example.com/story#comments`. Developer tools Network tab shows request line `GET /story` and the page is scrolled to a “Comments” heading.",
      "options": [
        {
          "feedback": "The fragment is the part after `#`. The browser uses it to jump to Comments on the already loaded page, and it is not included in the HTTP request line.",
          "isCorrect": true,
